def solve(roles, search_term):
    if not isinstance(roles, list) or not isinstance(search_term, str):
        return []

    search_term = search_term.lower()
    filtered_roles = []

    for role in roles:
        if 'admin' in role['name'].lower() or 'admin' in role['created_by'].lower():
            filtered_roles.append(role)

    return filtered_roles
